#!/usr/bin/env node
import http from 'node:http';
declare function getRepoDetails(): any[];
declare function getSkillsGrouped(): {
    domainGrouped: Record<string, any[]>;
    agentGrouped: Record<string, any[]>;
    commands: string[];
    totalDomain: number;
    totalAgent: number;
};
declare function getLearnings(): any[];
declare function getAutomation(): {
    scripts: {
        name: string;
        description: string;
    }[];
    botRunning: boolean;
    botCommands: string[];
};
